import math

def cap_parallel(caps):
    return math.fsum(caps)

def cap_series(caps):
    return 1 / math.fsum(1 / c for c in caps)

if __name__ == "__main__":
    print(f"Parallel: {cap_parallel([5.7, 12.3])}")
